    42→function Stars({ rating }: { rating: number }) {
    43→  const full = Math.floor(rating);
    44→  const half = rating - full >= 0.5;
    45→  return (
    46→    <span className="flex items-center gap-0.5">
    47→      {Array.from({ length: 5 }).map((_, i) => (
    48→        <i
    49→          key={i}
    50→          className={`ti text-xs ${
    51→            i < full ? "ti-star-filled text-amber-400" :
    52→            i === full && half ? "ti-star-half-filled text-amber-400" :
    53→            "ti-star text-slate-200"
    54→          }`}
    55→        />
    56→      ))}
