    61→function exportCSV(rows: PlaceResult[]) {
    62→  const header = "Nombre,Dirección,Teléfono,Sitio web,Calificación,Reseñas,Estado";
    63→  const lines = rows.map((r) =>
    64→    [r.name, r.address, r.phone, r.website, r.rating, r.reviews,
    65→      STATUS_MAP[r.status]?.label ?? r.status]
    66→      .map((v) => `"${String(v).replace(/"/g, '""')}"`)
    67→      .join(",")
    68→  );
    69→  const blob = new Blob([[header, ...lines].join("\n")], { type: "text/csv;charset=utf-8;" });
    70→  const a = document.createElement("a");
    71→  a.href = URL.createObjectURL(blob);
    72→  a.download = `leads-googlemaps-${Date.now()}.csv`;
    73→  a.click();
    74→}
