    76→async function apiFetch(url: string, opts?: RequestInit) {
    77→  const r = await fetch(url, { credentials: "include", ...opts });
    78→  if (!r.ok) throw new Error(`${r.status}: ${await r.text()}`);
    79→  return r.json();
    80→}
