    39→async function searchGooglePlaces(
    40→  query: string,
    41→  location: string,
    42→  maxResults: number,
    43→  apiKey: string
    44→): Promise<PlaceResult[]> {
    45→  const fullQuery = `${query} en ${location}`;
    46→  const url = "https://places.googleapis.com/v1/places:searchText";
    47→  const body = {
    48→    textQuery: fullQuery,
    49→    maxResultCount: Math.min(maxResults, 20),
    50→    languageCode: "es",
    51→  };
    52→
    53→  const resp = await fetch(url, {
    54→    method: "POST",
    55→    headers: {
    56→      "Content-Type": "application/json",
    57→      "X-Goog-Api-Key": apiKey,
    58→      "X-Goog-FieldMask":
    59→        "places.id,places.displayName,places.formattedAddress,places.nationalPhoneNumber,places.websiteUri,places.rating,places.userRatingCount,places.businessStatus",
    60→    },
    61→    body: JSON.stringify(body),
    62→  });
    63→
    64→  if (!resp.ok) {
    65→    const text = await resp.text();
    66→    throw new Error(`Google Places API error ${resp.status}: ${text}`);
    67→  }
    68→
    69→  const data = (await resp.json()) as {
    70→    places?: {
    71→      id?: string;
    72→      displayName?: { text?: string };
    73→      formattedAddress?: string;
    74→      nationalPhoneNumber?: string;
    75→      websiteUri?: string;
    76→      rating?: number;
    77→      userRatingCount?: number;
    78→      businessStatus?: string;
    79→    }[];
    80→  };
    81→
    82→  const places = data.places ?? [];
    83→  return places.map((p, i) => ({
    84→    id: p.id ?? `place_${i}`,
    85→    name: p.displayName?.text ?? "Sin nombre",
    86→    address: p.formattedAddress ?? "",
    87→    phone: p.nationalPhoneNumber ?? "",
    88→    website: p.websiteUri ?? "",
    89→    rating: p.rating ?? 0,
    90→    reviews: p.userRatingCount ?? 0,
    91→    status: p.businessStatus ?? "UNKNOWN",
    92→  }));
    93→}
