                {f.label}
                {cnt > 0 && (
                  <span className={`ml-0.5 px-1 rounded-full text-[9px] font-bold ${active ? "bg-cl-accent/20 text-cl-accent" : "bg-silver/20 text-cool-steel/70"}`}>
                    {cnt}
                  </span>
                )}
              </button>
            );
          })}
