  const { query = "restaurante", location = "Neuquén Capital", maxResults = 20 } = req.body as {
    query?: string;
    location?: string;
    maxResults?: number;
  };

  const [userConfig] = await db
    .select({ googleMapsApiKey: chatbotConfigsTable.googleMapsApiKey })
    .from(chatbotConfigsTable)
    .where(eq(chatbotConfigsTable.userId, (req.user as { id: string }).id))
    .limit(1);

  const apiKey = userConfig?.googleMapsApiKey?.trim() || process.env.GOOGLE_MAPS_API_KEY || "";

  if (!apiKey) {
    const sliced = DEMO_RESULTS.slice(0, Math.min(Number(maxResults), DEMO_RESULTS.length));
    res.json({ results: sliced, demo: true, total: sliced.length });
    return;
  }

  try {
    const results = await searchGooglePlaces(
      String(query),
      String(location),
      Number(maxResults),
      apiKey
    );
    res.json({ results, demo: false, total: results.length });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Error desconocido";
    res.status(500).json({ error: message });
  }
});

router.post("/prospector/import", async (req: Request, res: Response) => {
  if (!req.isAuthenticated()) {
    res.status(401).json({ error: "No autenticado" });
    return;
  }

  const userId = (req.user as { id: string }).id;
  const { leads } = req.body as {
    leads?: Array<{
      id: string;
      name: string;
      address: string;
      phone: string;
      website: string;
      rating: number;
      reviews: number;
      status: string;
    }>;
  };

  if (!Array.isArray(leads) || leads.length === 0) {
    res.status(400).json({ error: "Se requiere al menos un lead" });
    return;
  }

  let imported = 0;
  let duplicates = 0;

  for (const lead of leads) {
    const phone = lead.phone?.trim() || `sin-tel-${lead.id}`;

    const existing = await db
      .select({ id: conversationsTable.id })
      .from(conversationsTable)
      .where(and(
        eq(conversationsTable.userId, userId),
        eq(conversationsTable.phoneNumber, phone),
      ))
      .limit(1);

    if (existing.length > 0) {
      duplicates++;
      continue;
    }

    const noteParts: string[] = [];
    if (lead.address) noteParts.push(`Dirección: ${lead.address}`);
    if (lead.website) noteParts.push(`Web: ${lead.website}`);
    if (lead.rating > 0) noteParts.push(`Rating: ${lead.rating.toFixed(1)} ★ (${lead.reviews} reseñas)`);
    noteParts.push("Origen: Google Maps / Prospector");

    await db.insert(conversationsTable).values({
      id: crypto.randomUUID(),
      userId,
      phoneNumber: phone,
      contactName: lead.name || null,
      channel: "prospector",
      leadStatus: "new",
      leadNotes: noteParts.join(" | "),
      lastMessageAt: new Date(),
    });

    imported++;
  }

  res.json({ imported, duplicates, total: leads.length });
});

