    [["contable", "contador", "contaduria", "contaduría"], '["office"="accountant"]'],
    [["agencia", "agencia de viajes", "turismo"], '["shop"="travel_agency"]'],
    [["autopartes", "repuesto", "repuestos"], '["shop"="car_parts"]'],
