}

function buildAddressFromTags(tags: Record<string, string>): string {
  const parts: string[] = [];
  if (tags["addr:street"]) {
    parts.push(tags["addr:street"] + (tags["addr:housenumber"] ? " " + tags["addr:housenumber"] : ""));
  }
  if (tags["addr:city"]) parts.push(tags["addr:city"]);
  if (tags["addr:state"]) parts.push(tags["addr:state"]);
  return parts.join(", ") || tags["addr:full"] || "";
}

async function geocodeLocation(location: string): Promise<{ lat: string; lon: string; displayName: string } | null> {
  const url = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(location + " Argentina")}&format=json&limit=1&addressdetails=0`;
  try {
    const resp = await fetch(url, {
      headers: { "User-Agent": "Clientum-Prospector/1.0 (clientumlatam@gmail.com)" },
    });
    if (!resp.ok) return null;
    const data = (await resp.json()) as Array<{ lat: string; lon: string; display_name: string }>;
    if (!data.length) return null;
    return { lat: data[0].lat, lon: data[0].lon, displayName: data[0].display_name };
  } catch {
    return null;
  }
}

async function searchOverpassPlaces(
  query: string,
  location: string,
  maxResults: number
): Promise<PlaceResult[]> {
  const geo = await geocodeLocation(location);
  if (!geo) throw new Error(`No se encontró la ubicación: "${location}". Intentá con el nombre de la ciudad más completo.`);

  const { lat, lon } = geo;
  const radius = 8000;

  const osmTags = mapQueryToOSMTag(query);

  const nodesParts = osmTags.map(t => `node${t}(around:${radius},${lat},${lon});`).join("\n      ");
  const waysParts = osmTags.map(t => `way${t}(around:${radius},${lat},${lon});`).join("\n      ");

  const overpassQuery = `[out:json][timeout:30];
(
  ${nodesParts}
  ${waysParts}
);
out body;`;

  const overpassResp = await fetch("https://overpass-api.de/api/interpreter", {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: `data=${encodeURIComponent(overpassQuery)}`,
  });

  if (!overpassResp.ok) {
    throw new Error(`Error en OpenStreetMap (${overpassResp.status}). Intentá de nuevo en un momento.`);
  }

  const data = (await overpassResp.json()) as {
    elements: Array<{
      id: number;
      type: string;
      lat?: number;
      lon?: number;
      tags?: Record<string, string>;
    }>;
  };

  const seen = new Set<string>();
  const results: PlaceResult[] = [];

  for (const el of data.elements) {
    const tags = el.tags ?? {};
    const name = tags.name || tags["name:es"] || "";
    if (!name) continue;

    const key = name.toLowerCase().trim();
    if (seen.has(key)) continue;
    seen.add(key);

    const phone = tags.phone || tags["contact:phone"] || tags["phone:mobile"] || "";
    const website = tags.website || tags["contact:website"] || tags["url"] || "";
    const address = buildAddressFromTags(tags);

    results.push({
      id: `osm_${el.type}_${el.id}`,
      name,
      address,
      phone: phone.replace(/^(\+54)/, "+54").trim(),
      website: website.startsWith("http") ? website : (website ? "https://" + website : ""),
      rating: 0,
      reviews: 0,
      status: tags.opening_hours ? "OPERATIONAL" : "OPERATIONAL",
      source: "openstreetmap",
    });

    if (results.length >= maxResults) break;
  }

  return results;
}

/* ─── Google Maps Places API (pago, con key propia del usuario) ─── */

async function searchGooglePlaces(
  query: string,
  location: string,
  maxResults: number,
  apiKey: string
): Promise<PlaceResult[]> {
  const fullQuery = `${query} en ${location}`;
  const url = "https://places.googleapis.com/v1/places:searchText";
  const body = {
    textQuery: fullQuery,
    maxResultCount: Math.min(maxResults, 20),
    languageCode: "es",
  };

  const resp = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Goog-Api-Key": apiKey,
      "X-Goog-FieldMask":
        "places.id,places.displayName,places.formattedAddress,places.nationalPhoneNumber,places.websiteUri,places.rating,places.userRatingCount,places.businessStatus",
    },
    body: JSON.stringify(body),
  });

  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`Google Places API error ${resp.status}: ${text}`);
  }

  const data = (await resp.json()) as {
    places?: {
      id?: string;
      displayName?: { text?: string };
      formattedAddress?: string;
      nationalPhoneNumber?: string;
      websiteUri?: string;
      rating?: number;
      userRatingCount?: number;
      businessStatus?: string;
    }[];
  };

  const places = data.places ?? [];
  return places.map((p, i) => ({
    id: p.id ?? `place_${i}`,
    name: p.displayName?.text ?? "Sin nombre",
    address: p.formattedAddress ?? "",
    phone: p.nationalPhoneNumber ?? "",
    website: p.websiteUri ?? "",
    rating: p.rating ?? 0,
    reviews: p.userRatingCount ?? 0,
    status: p.businessStatus ?? "UNKNOWN",
    source: "google" as const,
  }));
}

/* ─── Routes ─── */

router.post("/prospector/search", async (req: Request, res: Response) => {
  if (!req.isAuthenticated()) {
    res.status(401).json({ error: "No autenticado" });
    return;
  }

  const { query = "restaurante", location = "Neuquén Capital", maxResults = 20 } = req.body as {
    query?: string;
    location?: string;
