  };

  const [userConfig] = await db
    .select({ googleMapsApiKey: chatbotConfigsTable.googleMapsApiKey })
    .from(chatbotConfigsTable)
    .where(eq(chatbotConfigsTable.userId, (req.user as { id: string }).id))
    .limit(1);

  const googleApiKey = userConfig?.googleMapsApiKey?.trim() || process.env.GOOGLE_MAPS_API_KEY || "";

  if (googleApiKey) {
    try {
      const results = await searchGooglePlaces(String(query), String(location), Number(maxResults), googleApiKey);
      res.json({ results, demo: false, source: "google", total: results.length });
      return;
    } catch (err) {
      const message = err instanceof Error ? err.message : "Error desconocido";
      res.status(500).json({ error: message });
      return;
    }
  }

  try {
    const results = await searchOverpassPlaces(String(query), String(location), Number(maxResults));
    res.json({ results, demo: false, source: "openstreetmap", total: results.length });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Error desconocido";
    res.status(500).json({ error: `Error al buscar en OpenStreetMap: ${message}` });
  }
