  const userId = (req.user as { id: string }).id;
  const { leads } = req.body as {
    leads?: Array<{
      id: string;
      name: string;
      address: string;
      phone: string;
      website: string;
      rating: number;
      reviews: number;
      status: string;
    }>;
  };

  if (!Array.isArray(leads) || leads.length === 0) {
    res.status(400).json({ error: "Se requiere al menos un lead" });
    return;
  }

  let imported = 0;
  let duplicates = 0;

  for (const lead of leads) {
    const phone = lead.phone?.trim() || `sin-tel-${lead.id}`;

    const existing = await db
      .select({ id: conversationsTable.id })
      .from(conversationsTable)
      .where(and(
        eq(conversationsTable.userId, userId),
        eq(conversationsTable.phoneNumber, phone),
      ))
      .limit(1);

    if (existing.length > 0) {
      duplicates++;
      continue;
    }

    const noteParts: string[] = [];
    if (lead.address) noteParts.push(`Dirección: ${lead.address}`);
    if (lead.website) noteParts.push(`Web: ${lead.website}`);
    if (lead.rating > 0) noteParts.push(`Rating: ${lead.rating.toFixed(1)} ★ (${lead.reviews} reseñas)`);
    noteParts.push("Origen: OpenStreetMap / Prospector");

    await db.insert(conversationsTable).values({
      id: crypto.randomUUID(),
      userId,
      phoneNumber: phone,
      contactName: lead.name || null,
      channel: "prospector",
      leadStatus: "new",
      leadNotes: noteParts.join(" | "),
      lastMessageAt: new Date(),
    });

    imported++;
  }

  res.json({ imported, duplicates, total: leads.length });
});

export default router;

