@keyframes mq-scroll { from { transform: translateX(0); } to { transform: translateX(-50%); } }
@keyframes mq-scroll-rev { from { transform: translateX(-50%); } to { transform: translateX(0); } }
.mq-track { display: flex; gap: 12px; width: max-content; animation: mq-scroll 28s linear infinite; }
.mq-track.rev { animation: mq-scroll-rev 34s linear infinite; }
.mq-mask { overflow: hidden; -webkit-mask-image: linear-gradient(to right, transparent 0%, black 10%, black 90%, transparent 100%); mask-image: linear-gradient(to right, transparent 0%, black 10%, black 90%, transparent 100%); }
.mq-mask:hover .mq-track { animation-play-state: paused; }
.planes-tog { width: 44px; height: 24px; border-radius: 100px; background: #DDDFE2; border: 1px solid rgba(3,30,67,.12); cursor: pointer; position: relative; flex-shrink: 0; transition: background .2s; display: inline-block; }
.planes-tog.on { background: #031E43; }
.planes-tog-thumb { position: absolute; top: 3px; left: 3px; width: 16px; height: 16px; border-radius: 50%; background: #fff; transition: transform .2s; }
.planes-tog.on .planes-tog-thumb { transform: translateX(20px); }
.pc-chk { width: 16px; height: 16px; border-radius: 50%; flex-shrink: 0; display: flex; align-items: center; justify-content: center; font-size: 8px; font-weight: 800; line-height: 1; }
.pc-chk.g { background: rgba(255,255,255,.15); border: 1px solid rgba(255,255,255,.3); color: #fff; }
.pc-chk.b { background: rgba(255,255,255,.15); border: 1px solid rgba(255,255,255,.3); color: #fff; }
.pc-chk.x { background: rgba(255,255,255,.04); border: 1px solid rgba(255,255,255,.08); color: rgba(255,255,255,.3); }
/* ── Plan cards dark ── */
.pc { background: #062040; border: 1px solid rgba(255,255,255,.08); border-radius: 18px; padding: 26px 22px 24px; position: relative; transition: border-color .22s, transform .22s; display: flex; flex-direction: column; }
.pc:hover { border-color: rgba(255,255,255,.3); transform: translateY(-3px); }
.pc.free { border-style: dashed; }
.pc.feat { background: #031E43; border: 2px solid rgba(255,255,255,.4); padding: 36px 22px 28px; box-shadow: 0 0 60px rgba(255,255,255,.06), 0 24px 48px rgba(0,0,0,.4); }
.pc.feat:hover { border-color: rgba(255,255,255,.7); }
.pc-badge { position: absolute; top: -13px; left: 50%; transform: translateX(-50%); font-size: 10px; font-weight: 800; letter-spacing: .07em; text-transform: uppercase; padding: 4px 14px; border-radius: 100px; white-space: nowrap; }
.pc-badge.green { background: #fff; color: #031E43; box-shadow: 0 3px 14px rgba(3,30,67,.15); }
.pc-badge.free-b { background: #111F45; color: rgba(255,255,255,.6); border: 1px solid rgba(255,255,255,.08); }
.pc-feats { list-style: none; display: flex; flex-direction: column; gap: 8px; margin-bottom: 22px; flex: 1; }
.pc-feats li { display: flex; align-items: flex-start; gap: 8px; font-size: 12.5px; color: rgba(255,255,255,.9); line-height: 1.4; }
.pc-feats li.dim { color: rgba(255,255,255,.5); }
/* ── Partner tier cards (light) ── */
.pt-grid { display: grid; grid-template-columns: repeat(3,1fr); gap: 20px; max-width: 1000px; margin: 0 auto 60px; }
@media (max-width: 800px) { .pt-grid { grid-template-columns: 1fr; max-width: 440px; } }
.pt-card { background: #fff; border: 1px solid #DDDFE2; border-radius: 20px; padding: 30px 26px 26px; transition: border-color .22s, transform .22s; display: flex; flex-direction: column; box-shadow: 0 2px 12px rgba(3,30,67,.06); }
.pt-card:hover { transform: translateY(-4px); box-shadow: 0 8px 32px rgba(3,30,67,.1); }
.pt-card.silver:hover { border-color: rgba(3,30,67,.25); }
.pt-card.gold { border: 1.5px solid rgba(3,30,67,.2); background: linear-gradient(160deg, rgba(3,30,67,.03) 0%, #fff 60%); }
.pt-card.gold:hover { border-color: rgba(3,30,67,.45); }
.pt-card.plat { border: 1.5px solid rgba(3,30,67,.3); background: linear-gradient(160deg, rgba(3,30,67,.05) 0%, #fff 60%); }
.pt-card.plat:hover { border-color: rgba(3,30,67,.6); }
/* ── Markdown body renderer (md-body) ── */
.md-body { color: rgba(255,255,255,.78); font-size: 13.5px; line-height: 1.7; }
.md-body .md-h1 { font-size: 1.5rem; font-weight: 800; color: #fff; margin: 1.5rem 0 .75rem; }
.md-body .md-h2 { font-size: 1.1rem; font-weight: 700; color: #fff; margin: 2rem 0 .6rem; padding-bottom: .4rem; border-bottom: 1px solid rgba(255,255,255,.07); }
.md-body .md-h3 { font-size: .95rem; font-weight: 700; color: rgba(255,255,255,.85); margin: 1.4rem 0 .4rem; }
.md-body .md-h4 { font-size: .875rem; font-weight: 700; color: rgba(255,255,255,.7); margin: 1rem 0 .3rem; }
.md-body .md-p { margin: .35rem 0; color: rgba(255,255,255,.72); font-size: 13.5px; }
.md-body .md-hr { border: none; border-top: 1px solid rgba(255,255,255,.07); margin: 1.5rem 0; }
.md-body .md-spacer { height: .4rem; }
.md-body .md-blockquote { border-left: 2px solid rgba(255,255,255,.4); padding-left: 1rem; margin: .75rem 0; color: rgba(255,255,255,.55); font-style: italic; font-size: 13px; }
.md-body .md-list { list-style: none; padding: 0; margin: .4rem 0 .4rem .5rem; }
.md-body .md-li { padding: .2rem 0; color: rgba(255,255,255,.78); font-size: 13.5px; position: relative; padding-left: 1rem; }
.md-body .md-li::before { content: "•"; position: absolute; left: 0; color: rgba(255,255,255,.5); }
.md-body .md-checklist { list-style: none; padding: 0; margin: .3rem 0; }
.md-body .md-check-item { display: flex; align-items: flex-start; gap: .5rem; padding: .3rem .4rem; border-radius: .5rem; }
.md-body .md-check-item.checked { opacity: .5; }
.md-body .md-check-item.checked .check-text { text-decoration: line-through; }
.md-body .check-box { width: 1rem; height: 1rem; flex-shrink: 0; margin-top: .15rem; border-radius: .25rem; background: rgba(255,255,255,.15); border: 1px solid rgba(255,255,255,.3); display: flex; align-items: center; justify-content: center; font-size: 9px; color: #fff; }
.md-body .md-check-item.unchecked .check-box { background: rgba(255,255,255,.03); border: 1px solid rgba(255,255,255,.15); }
.md-body .check-text { font-size: 13px; color: rgba(255,255,255,.82); line-height: 1.5; }
.md-body .md-check-item.pri-red .check-text { color: rgba(255,255,255,.9); }
.md-body .inline-code { background: rgba(255,255,255,.06); padding: .1rem .35rem; border-radius: .3rem; font-size: 11.5px; font-family: ui-monospace, monospace; color: rgba(255,255,255,.9); }
.md-body .md-link { color: #60a5fa; text-decoration: underline; }
.md-body .md-code { background: rgba(0,0,0,.35); border: 1px solid rgba(255,255,255,.07); border-radius: .75rem; padding: 1rem 1.25rem; overflow-x: auto; margin: .75rem 0; font-family: ui-monospace, monospace; font-size: 12px; color: rgba(255,255,255,.8); white-space: pre; }
.md-body .md-table-wrap { overflow-x: auto; margin: .75rem 0; }
.md-body .md-table { width: 100%; border-collapse: collapse; font-size: 12.5px; }
.md-body .md-table th { text-align: left; padding: .45rem .75rem; color: rgba(255,255,255,.45); font-weight: 700; font-size: 10.5px; text-transform: uppercase; letter-spacing: .05em; border-bottom: 1px solid rgba(255,255,255,.06); }
.md-body .md-table td { padding: .4rem .75rem; color: rgba(255,255,255,.72); border-bottom: 1px solid rgba(255,255,255,.03); font-size: 12.5px; }
.md-body .md-table tr:hover td { background: rgba(255,255,255,.02); }
.md-body strong { color: rgba(255,255,255,.95); font-weight: 600; }
.md-body em { color: rgba(255,255,255,.8); }

/* integration pills light */
.int-pill { display: inline-flex; align-items: center; gap: 9px; background: #fff; border: 1px solid #DDDFE2; border-radius: 100px; padding: 9px 18px; white-space: nowrap; transition: border-color .2s, box-shadow .2s; font-size: 13px; font-weight: 600; color: #031E43; }
.int-pill:hover { border-color: rgba(3,30,67,.4); box-shadow: 0 2px 8px rgba(3,30,67,.08); }

